// Converts every PNG in public/blog-images/ to WebP at quality 82.
// Idempotent: skips a file if its `.webp` counterpart already exists and is
// newer. Keeps the original PNG on disk as a fallback so the site never breaks
// during the rollout (heroImageFor prefers .webp but falls back to .png).
//
// Run with:    node scripts/optimize-blog-images.mjs
//
// Typical reduction observed on the 26 blog hero panels generated by Imagen 4 /
// Gemini Flash Image: 1.4 MB PNG → ~250 KB WebP at q=82 (≈ 80% smaller),
// visually indistinguishable.

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import sharp from 'sharp';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const DIR = path.join(ROOT, 'public', 'blog-images');

if (!fs.existsSync(DIR)) {
  console.error(`Directory not found: ${DIR}`);
  process.exit(1);
}

const pngs = fs.readdirSync(DIR).filter((f) => f.toLowerCase().endsWith('.png'));
console.log(`Found ${pngs.length} PNG files in ${DIR}\n`);

let totalIn = 0;
let totalOut = 0;
let processed = 0;
let skipped = 0;
let failed = 0;

for (const png of pngs) {
  const srcPath = path.join(DIR, png);
  const dstPath = path.join(DIR, png.replace(/\.png$/i, '.webp'));

  const inSize = fs.statSync(srcPath).size;
  totalIn += inSize;

  if (fs.existsSync(dstPath) && fs.statSync(dstPath).mtimeMs >= fs.statSync(srcPath).mtimeMs) {
    const outSize = fs.statSync(dstPath).size;
    totalOut += outSize;
    skipped++;
    console.log(`-  skip   ${png}  (webp already up-to-date, ${(outSize / 1024).toFixed(0)} KB)`);
    continue;
  }

  try {
    await sharp(srcPath)
      .webp({ quality: 82, effort: 5 })
      .toFile(dstPath);
    const outSize = fs.statSync(dstPath).size;
    totalOut += outSize;
    processed++;
    const reduction = ((1 - outSize / inSize) * 100).toFixed(0);
    console.log(`✓  done   ${png.padEnd(60)}  ${(inSize / 1024).toFixed(0).padStart(5)} KB  →  ${(outSize / 1024).toFixed(0).padStart(4)} KB  (-${reduction}%)`);
  } catch (e) {
    failed++;
    console.log(`✗  fail   ${png}  — ${e.message}`);
  }
}

console.log(`\nSummary:`);
console.log(`  Files processed:  ${processed}`);
console.log(`  Files skipped:    ${skipped}`);
console.log(`  Files failed:     ${failed}`);
console.log(`  Total in (PNG):   ${(totalIn / 1024 / 1024).toFixed(1)} MB`);
console.log(`  Total out (WebP): ${(totalOut / 1024 / 1024).toFixed(1)} MB`);
const reduction = totalIn > 0 ? ((1 - totalOut / totalIn) * 100).toFixed(0) : 0;
console.log(`  Saved:            ${((totalIn - totalOut) / 1024 / 1024).toFixed(1)} MB  (-${reduction}%)`);
